import {
  circle, ellipse, rectangle, rounded_rectangle, polygon, triangle,
  segment, arc, ring, trapezoid,
  union, intersection, difference, dilate, erode, shell,
  render,
} from '../../src/index.js';

// --- Palette ---
const OCEAN_DEEP   = [18, 52, 88];
const OCEAN_MID    = [28, 78, 130];
const OCEAN_FOAM   = [162, 198, 220];
const HULL_DARK    = [38, 48, 62];
const HULL_GRAY    = [82, 92, 108];
const DECK_GRAY    = [118, 128, 138];
const DECK_LIGHT   = [158, 165, 172];
const ISLAND_GRAY  = [96, 104, 116];
const RED_STRIPE   = [180, 32, 32];
const SKY_TOP      = [42, 78, 130];
const SKY_MID      = [108, 158, 195];
const SKY_HORIZON  = [198, 218, 228];
const WAKE_WHITE   = [220, 230, 238];
const OUTLINE      = [18, 22, 28];
const JET_GRAY     = [72, 80, 90];
const JET_DARK     = [48, 55, 65];
const EXHAUST      = [160, 140, 110];

// --- Sea & Sky Background ---
const sky = rectangle([2.6, 1.6], [0, 0.5]);
const sea = rectangle([2.6, 0.8], [0, -0.55]);

// --- Sea surface layering ---
const seaSurface   = rectangle([2.6, 0.05], [0, -0.18]);
const waveHint1    = ellipse(0.6, 0.018, [-0.5, -0.20]);
const waveHint2    = ellipse(0.4, 0.012, [0.5, -0.22]);
const waveHint3    = ellipse(0.3, 0.010, [0.1, -0.24]);

// Wake: white foam trailing behind (left side, since ship faces right)
const wakeFoam     = ellipse(0.55, 0.06, [-0.75, -0.28]);
const wakeFoam2    = ellipse(0.35, 0.035, [-0.85, -0.32]);

// --- Hull ---
// The carrier hull: long, flat-bottomed, slight bow shaping
const hullMain = polygon([
  [-0.88, -0.18],
  [ 0.82, -0.18],   // forward bow upper
  [ 0.92, -0.22],   // bow tip
  [ 0.82, -0.34],   // forward waterline
  [-0.88, -0.34],   // aft waterline
  [-0.94, -0.26],   // aft stern
]);

// Red waterline stripe
const waterlineStripe = intersection(
  hullMain,
  rectangle([2.2, 0.028], [0, -0.31])
);

// Hull boot topping (dark bottom, red stripe, gray top)
const hullBottom = intersection(
  hullMain,
  rectangle([2.2, 0.065], [0, -0.32])
);

// --- Flight Deck ---
// Wide, long deck overhanging hull on both sides (ski-jump bow on right)
const deckMain = polygon([
  [-0.90, -0.18],
  [ 0.78, -0.18],
  [ 0.92, -0.08],   // ski-jump slope
  [ 0.94,  0.00],   // ski-jump tip
  [ 0.78,  0.02],   // forward deck edge
  [-0.90,  0.02],   // aft deck edge
]);

// Ski-jump ramp (lighter highlight)
const skiJump = polygon([
  [0.72, -0.01],
  [0.84, -0.14],
  [0.92, -0.08],
  [0.94,  0.00],
  [0.80,  0.02],
]);

// Deck centerline stripe (yellow / white): just a thin rect
const deckCenterline = intersection(
  deckMain,
  rectangle([1.80, 0.006], [-0.05, -0.06])
);

// Deck edge markings
const deckEdgePort = intersection(
  deckMain,
  rectangle([1.82, 0.006], [-0.05, -0.17])
);

// --- Island Superstructure ---
// China carriers (Liaoning, Shandong) have island on starboard (right),
// aft-of-center. Relatively compact.
const islandBase = rounded_rectangle([0.26, 0.22], 0.02, [0.30, -0.08]);
const islandMid  = rounded_rectangle([0.20, 0.14], 0.02, [0.31, 0.06]);
const islandTop  = rounded_rectangle([0.16, 0.08], 0.015, [0.30, 0.17]);
const island     = union(islandBase, islandMid, islandTop);

// Windows on island
const win1 = rectangle([0.04, 0.025], [0.22, -0.04]);
const win2 = rectangle([0.04, 0.025], [0.30, -0.04]);
const win3 = rectangle([0.04, 0.025], [0.38, -0.04]);
const islandWindows = union(win1, win2, win3);

// Mast / radar tower
const mast1 = segment([0.30, 0.20], [0.30, 0.42], 0.006);
const mast2 = segment([0.24, 0.28], [0.36, 0.28], 0.004);  // cross-spar

// Phased-array radar panels (Type 346 style — 4-face AESA)
const radar1 = rectangle([0.07, 0.045], [0.30, 0.34]);
const radar2 = rectangle([0.045, 0.07], [0.27, 0.28]);
const radar3 = rectangle([0.045, 0.07], [0.33, 0.28]);
const radars = union(radar1, radar2, radar3);

// HQ-10 CIWS domes (close-in weapon systems) — small circles
const ciws1 = circle(0.022, [-0.60,  0.04]);
const ciws2 = circle(0.022, [-0.10,  0.04]);
const ciws3 = circle(0.022, [ 0.55,  0.04]);
const ciws4 = circle(0.018, [ 0.60, -0.10]);
const ciwsAll = union(ciws1, ciws2, ciws3, ciws4);

// --- Aircraft on deck (J-15 silhouettes) ---
// Three fighters parked on deck near bow and island
function jet(cx, cy, scale = 1.0) {
  const body   = ellipse(0.07 * scale, 0.018 * scale, [cx, cy]);
  const wing1  = polygon([
    [cx - 0.01 * scale, cy + 0.006 * scale],
    [cx + 0.05 * scale, cy + 0.008 * scale],
    [cx - 0.04 * scale, cy + 0.048 * scale],
    [cx - 0.06 * scale, cy + 0.038 * scale],
  ]);
  const wing2  = polygon([
    [cx - 0.01 * scale, cy - 0.006 * scale],
    [cx + 0.05 * scale, cy - 0.008 * scale],
    [cx - 0.04 * scale, cy - 0.048 * scale],
    [cx - 0.06 * scale, cy - 0.038 * scale],
  ]);
  const tail1 = polygon([
    [cx - 0.055 * scale, cy + 0.005 * scale],
    [cx - 0.065 * scale, cy + 0.025 * scale],
    [cx - 0.085 * scale, cy + 0.022 * scale],
    [cx - 0.075 * scale, cy + 0.004 * scale],
  ]);
  const tail2 = polygon([
    [cx - 0.055 * scale, cy - 0.005 * scale],
    [cx - 0.065 * scale, cy - 0.025 * scale],
    [cx - 0.085 * scale, cy - 0.022 * scale],
    [cx - 0.075 * scale, cy - 0.004 * scale],
  ]);
  return union(body, wing1, wing2, tail1, tail2);
}

const jet1 = jet( 0.50, -0.10, 0.90);  // near island
const jet2 = jet(-0.20, -0.12, 0.85);  // mid-deck
const jet3 = jet(-0.60, -0.10, 0.85);  // aft deck
const jetsAll = union(jet1, jet2, jet3);

// --- Five-star flag on mast ---
const flagPole = segment([0.18, 0.35], [0.18, 0.50], 0.004);
const flagBody = rectangle([0.09, 0.055], [0.226, 0.45]);
const bigStar  = circle(0.012, [0.208, 0.455]);
// small stars omitted for scale — flag reads as red block

// --- Smoke / exhaust from island ---
const exhaust1 = ellipse(0.022, 0.032, [0.25, 0.48]);
const exhaust2 = ellipse(0.018, 0.026, [0.22, 0.52]);
const exhaust3 = ellipse(0.015, 0.020, [0.20, 0.55]);

// --- Compose layers ---
const layers = [
  // Sky gradient approximated as two rects
  { sdf: sky,            color: SKY_TOP },
  { sdf: rectangle([2.6, 0.60], [0, 0.15]),  color: SKY_MID },
  { sdf: rectangle([2.6, 0.30], [0, -0.05]), color: SKY_HORIZON },

  // Sea
  { sdf: sea,            color: OCEAN_DEEP },
  { sdf: rectangle([2.6, 0.55], [0, -0.40]), color: OCEAN_MID },
  { sdf: seaSurface,     color: OCEAN_FOAM },
  { sdf: waveHint1,      color: OCEAN_FOAM },
  { sdf: waveHint2,      color: OCEAN_FOAM },
  { sdf: waveHint3,      color: OCEAN_FOAM },

  // Wake
  { sdf: wakeFoam,       color: WAKE_WHITE },
  { sdf: wakeFoam2,      color: WAKE_WHITE },

  // Hull outline
  { sdf: dilate(hullMain, 0.025), color: OUTLINE },
  // Hull fill
  { sdf: hullMain,       color: HULL_GRAY },
  // Hull bottom
  { sdf: hullBottom,     color: HULL_DARK },
  // Red waterline
  { sdf: waterlineStripe, color: RED_STRIPE },

  // Deck outline
  { sdf: dilate(deckMain, 0.018), color: OUTLINE },
  { sdf: deckMain,       color: DECK_GRAY },
  { sdf: skiJump,        color: DECK_LIGHT },
  { sdf: deckCenterline, color: DECK_LIGHT },
  { sdf: deckEdgePort,   color: DECK_LIGHT },

  // Jets
  { sdf: dilate(jetsAll, 0.010), color: OUTLINE },
  { sdf: jetsAll,        color: JET_DARK },

  // Island outline
  { sdf: dilate(island, 0.020), color: OUTLINE },
  { sdf: island,         color: ISLAND_GRAY },
  { sdf: difference(island, islandWindows), color: ISLAND_GRAY },
  { sdf: islandWindows,  color: HULL_DARK },

  // CIWS domes
  { sdf: dilate(ciwsAll, 0.008), color: OUTLINE },
  { sdf: ciwsAll,        color: DECK_LIGHT },

  // Mast and radar
  { sdf: mast1,          color: OUTLINE },
  { sdf: mast2,          color: OUTLINE },
  { sdf: dilate(radars, 0.007), color: OUTLINE },
  { sdf: radars,         color: ISLAND_GRAY },

  // Flag
  { sdf: flagPole,       color: OUTLINE },
  { sdf: dilate(flagBody, 0.006), color: OUTLINE },
  { sdf: flagBody,       color: RED_STRIPE },
  { sdf: bigStar,        color: [255, 215, 0] },

  // Exhaust
  { sdf: exhaust1,       color: EXHAUST },
  { sdf: exhaust2,       color: [192, 174, 148] },
  { sdf: exhaust3,       color: [210, 200, 185] },
];

// --- Render ---
const canvas = document.getElementById('c');
const ctx = canvas.getContext('2d');
render.silhouette(ctx, layers, {
  view: 1.25,
  background: { top: [32, 64, 110], bottom: [168, 200, 220] },
});
```

**Composition notes:**

**Subject**: 辽宁舰 / 山东舰造型参考——中国海军首型航母最显著特征是**滑跃式甲板**（ski-jump bow，向上翘起的舰艏）而非美军弹射式平甲板，岛式上层建筑配备**346型有源相控阵雷达**（四面阵天线）。三架 J-15 飞鲨舰载机停驻在甲板上，用翼型 polygon 勾勒出 delta 翼+鸭翼轮廓。

**层次结构**：天空（三段蓝色梯度）→ 海面（深→中→泡沫三层）→ 尾迹白浪 → 船体（灰色填充+红色水线漆）→ 飞行甲板（轻灰+滑跃坡高光）→ 舰载机 → 岛楼+雷达 → 旗杆+五星红旗+废气。每个主要元素都用 `dilate(..., t)` 打底再填色，轮廓厚度依视觉层级从 0.025（船体）递减至 0.007（雷达组件）。

**调色板**灵感来自解放军海军官方照片：深蓝洋面、中灰甲板、红色水线和五星旗是唯一鲜艳色彩，保持了军事题材的克制感，同时用暖色排烟云雾暗示动力。
